namespace optiling {

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    // Input shapes
    const gert::Shape *x_shape = context->GetInputShape(0);
    const gert::Shape *w_shape = context->GetInputShape(1);

    const int64_t N   = x_shape->GetOriginShape().GetDim(0);
    const int64_t Cin = x_shape->GetOriginShape().GetDim(1);
    const int64_t H   = x_shape->GetOriginShape().GetDim(2);
    const int64_t W   = x_shape->GetOriginShape().GetDim(3);

    const int64_t Cout = w_shape->GetOriginShape().GetDim(0);
    const int64_t Kh   = w_shape->GetOriginShape().GetDim(2);
    const int64_t Kw   = w_shape->GetOriginShape().GetDim(3);

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const float *subtractValue = attrs->GetAttrPointer<float>(0);
    const int64_t *poolKernelSz = attrs->GetAttrPointer<int64_t>(1);

    const int64_t Oh = H - Kh + 1;
    const int64_t Ow = W - Kw + 1;

    const int64_t Pk = *poolKernelSz;
    const int64_t Oh2 = (Oh > 0 && Pk > 0) ? (Oh / Pk) : 0;
    const int64_t Ow2 = (Ow > 0 && Pk > 0) ? (Ow / Pk) : 0;

    uint32_t hasBias = 0u;
    if (context->GetInputsSize() > 2) {
        const gert::Shape *b_shape = context->GetInputShape(2);
        if (b_shape != nullptr && b_shape->GetOriginShape().GetShapeSize() > 0) {
            hasBias = 1u;
        }
    }

    // Choose blocks across N * Cout
    uint32_t wantBlocks = static_cast<uint32_t>(N * Cout);
    uint32_t blockDim = ClampBlockDim(wantBlocks);
    context->SetBlockDim(blockDim);

    optiling::Conv2dSubtractHardSwishMaxPoolMishCustomTilingData tiling;
    tiling.set_N(static_cast<uint32_t>(N));
    tiling.set_Cin(static_cast<uint32_t>(Cin));
    tiling.set_H(static_cast<uint32_t>(H));
    tiling.set_W(static_cast<uint32_t>(W));
    tiling.set_Cout(static_cast<uint32_t>(Cout));
    tiling.set_Kh(static_cast<uint32_t>(Kh));
    tiling.set_Kw(static_cast<uint32_t>(Kw));
    tiling.set_Oh(static_cast<uint32_t>(Oh));
    tiling.set_Ow(static_cast<uint32_t>(Ow));
    tiling.set_Pk(static_cast<uint32_t>(Pk));
    tiling.set_Oh2(static_cast<uint32_t>(Oh2));
    tiling.set_Ow2(static_cast<uint32_t>(Ow2));
    tiling.set_hasBias(hasBias);
    tiling.set_blockDim(blockDim);
    tiling.set_subtractVal(*subtractValue);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *ws = context->GetWorkspaceSizes(1);
    ws[0] = 0;
    return ge::GRAPH_SUCCESS;
}

