                                                        const at::Tensor& w,
                                                        int64_t pool_kernel_size)
{
    const int64_t N = x.size(0);
    const int64_t H = x.size(2);
    const int64_t W = x.size(3);

    const int64_t Cout = w.size(0);
    const int64_t Kh = w.size(2);
    const int64_t Kw = w.size(3);

