    const int64_t Ow2 = (Ow > 0 && pool_kernel_size > 0) ? (Ow / pool_kernel_size) : 0;

    auto sizes = at::IntArrayRef({N, Cout, Oh2, Ow2});
    return at::empty(sizes, x.options());
